def _validate_card_number(card_number: str) -> str:
    """Strip spaces/dashes and do basic validation (Luhn check)."""
    cleaned = re.sub(r"[\s\-]", "", card_number)
    if not cleaned.isdigit():
        raise ValueError("Credit card number must contain only digits (and optional spaces/dashes).")
    if not (13 <= len(cleaned) <= 19):
        raise ValueError("Credit card number length must be between 13 and 19 digits.")
    if not _luhn_check(cleaned):
        raise ValueError("Credit card number fails Luhn check – invalid card number.")
    return cleaned


def _luhn_check(card_number: str) -> bool:
    """Validate a card number using the Luhn algorithm."""
    total = 0
    reverse_digits = card_number[::-1]
    for i, digit in enumerate(reverse_digits):
        n = int(digit)
        if i % 2 == 1:
            n *= 2
            if n > 9:
                n -= 9
        total += n
    return total % 10 == 0


